    @Override
    @InitializeAdmin
    @Transactional
    public void transferToEKalender(Admin admin, List<Integer> ids, LocalDate datum) {
        ids.forEach(id -> {
            GewaarborgdLoonSupplement gewaarborgdLoonSupplement = getGewaarborgdLoonSupplement(admin, id);
            if (gewaarborgdLoonSupplement != null) {
                String fout = validateGewaarborgdLoonSupplement(admin, gewaarborgdLoonSupplement);
                if (StringUtils.isBlank(fout)) {
                    gewaarborgdLoonSupplementService.markTransferredToEKalender(admin, gewaarborgdLoonSupplement.getId());
                    createKalOpdrachtLoonCode(admin, gewaarborgdLoonSupplement, datum);
                } else {
                    gewaarborgdLoonSupplementService.transferToEKalenderFout(admin, gewaarborgdLoonSupplement.getId(), fout);
                }
            } else {
                throw new MessageException("Gewaarborgd loon op supplementen met id " + id + " niet gevonden.");
            }
        });
    }

