    private void deleteKalOpdrachtLooncode(Admin admin, Integer id) {
        AardKodeExtensie aardKodeExtensie = aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(2, 3, 101, 50);

        GewaarborgdLoonSupplement gewaarborgdLoonSupplement = gewaarborgdLoonSupplementService.getById(admin, id);

        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("opdracht", EQ(gewaarborgdLoonSupplement.getOpdracht()));
        cb.and("referentiejaar", EQ(gewaarborgdLoonSupplement.getPeriode().getYear()));
        cb.and("referentiemaand", EQ(gewaarborgdLoonSupplement.getPeriode().getMonthOfYear()));
        cb.and("aardKodeExtensie", EQ(aardKodeExtensie));
        cb.and("kalOpdrachtLooncodeSlices.bron", EQ(KalenderPrestatieBron.GEWLOON));
        KalOpdrachtLooncode kalOpdrachtLooncode = kalOpdrachtLooncodeService.getByCriteria(admin, cb);

        if (kalOpdrachtLooncode != null) {
            kalOpdrachtLooncodeService.delete(admin, kalOpdrachtLooncode);
        }
    }

