    @Override
    public Prestatieverhouding getPrestatieverhouding(Opdracht opdracht) {
        Opper opperLaatsteGegevens = RekenTools.getOpperLaatsteGegevens(opdracht);
        SleutelGegevensSingleOpper sleutelGegevensSingleOpper = new SleutelGegevensSingleOpper(opperLaatsteGegevens);
        Breuk pvhBreuk = RkmPrestatieVerhouding.bepaalBreuk(sleutelGegevensSingleOpper, new RegulManagerImp());
        return new Prestatieverhouding(pvhBreuk.getTeller(), pvhBreuk.getNoemer());
    }

    private Prestatieverhouding getPrestatieverhouding(
            Opdracht opdracht, List<GewaarborgdLoonSupplementImportDTO> importsByOpdrachtPeriode, LocalDateInterval periode, LocalDateInterval periodeNlp) {
        BigDecimal totaalAantalDagen = new BigDecimal(Days.daysBetween(periode.getStart(), periode.getEnd()).getDays() + 1);
        BigDecimal nlpAantalDagen = periodeNlp != null ? new BigDecimal(Days.daysBetween(periodeNlp.getStart(), periodeNlp.getEnd()).getDays() + 1) : BigDecimal.ZERO;
        BigDecimal teller = BigDecimal.ZERO;
        BigDecimal noemer = BigDecimal.ZERO;

        for (GewaarborgdLoonSupplementImportDTO importByOpdrachtPeriode : importsByOpdrachtPeriode) {
            YearMonth month = new YearMonth(importByOpdrachtPeriode.getJaar(), importByOpdrachtPeriode.getMaand());
            BigDecimal aantalDagen = new BigDecimal(month.toLocalDate(1).plusMonths(1).minusDays(1).getDayOfMonth());
            teller = teller.add(importByOpdrachtPeriode.getTellerPvh().multiply(aantalDagen));
            noemer = importByOpdrachtPeriode.getNoemerPvh();
        }

        for (Opper opper : opdracht.getOpperSlices()) {
            if (periodeNlp != null && !opper.getActualTo().isBefore(periodeNlp.getStart()) && !opper.getActualFrom().isAfter(periodeNlp.getEnd())) {
                LocalDate startDatum = opper.getActualFrom().isBefore(periodeNlp.getStart()) ? periodeNlp.getStart() : opper.getActualFrom();
                LocalDate eindDatum = opper.getActualTo().isAfter(periodeNlp.getEnd()) ? periodeNlp.getEnd() : opper.getActualTo();
                BigDecimal aantalDagen = new BigDecimal(Days.daysBetween(startDatum, eindDatum).getDays() + 1);
                SleutelGegevensSingleOpper sleutelGegevensSingleOpper = new SleutelGegevensSingleOpper(opper);
                Breuk pvhBreuk = RkmPrestatieVerhouding.bepaalBreuk(sleutelGegevensSingleOpper, new RegulManagerImp());
                Prestatieverhouding prestatieverhouding = new Prestatieverhouding(pvhBreuk.getTeller(), pvhBreuk.getNoemer());
                teller = teller.add(prestatieverhouding.getTeller().multiply(aantalDagen));
                if (opper.getRszppo().getDienstverband().equals(Dienstverband.JA)) {
                    noemer = prestatieverhouding.getNoemer();
                }
            }

        }

        if (importsByOpdrachtPeriode.isEmpty() && nlpAantalDagen.signum() != 0) {
            teller = teller.divide(nlpAantalDagen, 2, RekenTools.DEFAULT_ROUNDING_MODE);
        } else {
            teller = teller.divide(totaalAantalDagen, 2, RekenTools.DEFAULT_ROUNDING_MODE);
        }

        return new Prestatieverhouding(teller, noemer.signum() != 0 ? noemer : BigDecimal.ONE);
    }

    private Prestatieverhouding getPrestatieverhouding(List<GewaarborgdLoonSupplementImportDTO> importsByOpdrachtPeriode) {
        Prestatieverhouding pvhImport;
        BigDecimal tellerImport = importsByOpdrachtPeriode.stream()
                .map(GewaarborgdLoonSupplementImportDTO::getTellerPvh)
                .reduce(BigDecimal.ZERO, BigDecimal::add)
                .divide(new BigDecimal(importsByOpdrachtPeriode.size()), 2, RekenTools.DEFAULT_ROUNDING_MODE);
        BigDecimal tellerNoemer = importsByOpdrachtPeriode.stream()
                .map(GewaarborgdLoonSupplementImportDTO::getNoemerPvh)
                .reduce(BigDecimal.ZERO, BigDecimal::add)
                .divide(new BigDecimal(importsByOpdrachtPeriode.size()), 2, RekenTools.DEFAULT_ROUNDING_MODE);
        pvhImport = new Prestatieverhouding(tellerImport, tellerNoemer);
        return pvhImport;
    }

    @Override
    public String berekenen(Admin admin, GewaarborgdLoonSupplementFilters filters) {
        if (SecurityContextHolder.getContext().getAuthentication() != null) {
            List<GewaarborgdLoonSupplementBerekenenProces> processen = gewaarborgdLoonProcesCentral.getProcessen(admin);
            for (GewaarborgdLoonSupplementBerekenenProces proces : processen) {
                if (!(proces.isFinished() || proces.getStopFlag())) {
                    throw new MessageException("Maximaal één proces tegelijk, er is al een proces bezig met rekenen.");
                }
            }
            return gewaarborgdLoonProcesCentral.startProces(admin, filters, this);
        }
        return null;
    }

