    @Override
    public void berekenenBedragen(Admin admin, GewaarborgdLoonSupplementFilters filters, IntConsumer sizeNotifier, Runnable verwerktNotifier) {
        LocalDateInterval monthUitbetaling = new Month(filters.getUitbetalingsperiode().toLocalDate(1));
        LocalDateInterval periode = new LocalDateInterval(filters.getPeriodeVan().toLocalDate(1),
                filters.getPeriodeTot().toLocalDate(1).dayOfMonth().withMaximumValue());
        Hoedanigheid hoedanigheid = Hoedanigheid.getByCode(filters.getHoedanigheid());
        List<Opdracht> opdrachten = opdrachtService.findByWerkgeverPeriode(admin, filters.getWerkgeverId(), periode)
                .stream()
                .filter(Objects::nonNull)
                .filter(opdracht -> opdracht.getOpdrachtSlices()
                        .stream()
                        .anyMatch(slice -> slice.getHoedanigheid() == hoedanigheid))
                .collect(Collectors.toList());
        LocalDate bestuurStartDatum = this.getBestuurStartDatum(admin);
        LocalDateInterval periodeImport;
        LocalDateInterval periodeNlp;
        if (periode.getStart().isBefore(bestuurStartDatum)) {
            periodeImport = new LocalDateInterval(periode.getStart(), bestuurStartDatum.minusDays(1));
            if (periode.getEnd().isAfter(bestuurStartDatum)) {
                periodeNlp = new LocalDateInterval(bestuurStartDatum, periode.getEnd());
            } else {
                periodeNlp = null;
            }

        } else {
            periodeImport = null;
            periodeNlp = periode;
        }

        sizeNotifier.accept(opdrachten.size());
        opdrachten.forEach(opdracht -> {
            berekenenBedrag(admin, opdracht, monthUitbetaling, periode, periodeImport, periodeNlp, filters.getActor());
            verwerktNotifier.run();
        });
    }

    @Override
    public byte[] exportExcel(Admin admin, Collection<GewaarborgdLoonSupplementDTO> gewaarborgdLoonSupplementen) {
        try (ByteArrayOutputStream baos = new ByteArrayOutputStream(); Workbook wb = new XSSFWorkbook()) {
            Sheet sheet = wb.createSheet();
            AtomicInteger rowIndex = new AtomicInteger();
            addHeaderToExcel(sheet, rowIndex);
            gewaarborgdLoonSupplementen.forEach(gewaarborgdLoonSupplement -> addRowToExcel(sheet, rowIndex, gewaarborgdLoonSupplement));
            IntStream.range(0, 16).forEach(sheet::autoSizeColumn);
            wb.write(baos);
            return baos.toByteArray();
        } catch (IOException e) {
            throw new MessageException("Een technische fout bij het maken van de excel", e);
        }
    }

