        row.createCell(cellIndex++).setCellValue("Opdrachtnummer");
        row.createCell(cellIndex++).setCellValue("Naam");
        row.createCell(cellIndex++).setCellValue("Periode");
        row.createCell(cellIndex++).setCellValue("PVH");
        row.createCell(cellIndex++).setCellValue("Gelijkgestelde coëfficient");
        row.createCell(cellIndex++).setCellValue("Effectieve dagen coëfficient");
        row.createCell(cellIndex++).setCellValue("Variabel loon");
        row.createCell(cellIndex++).setCellValue("Dagen teller 1");
        row.createCell(cellIndex++).setCellValue("Bedrag supplement");
        row.createCell(cellIndex++).setCellValue("Verwerkt");
        row.createCell(cellIndex++).setCellValue("Datum verwerkt");
        row.createCell(cellIndex++).setCellValue("Verwerkt door");
        row.createCell(cellIndex++).setCellValue("Foutboodschap");
        row.createCell(cellIndex++).setCellValue("Tijdstip berekenen");
        row.createCell(cellIndex).setCellValue("Berekend door");
    }

    private void addRowToExcel(Sheet sheet, AtomicInteger rowIndex, GewaarborgdLoonSupplementDTO gewaarborgdLoonSupplement) {
        int cellIndex = 0;
        Row row = sheet.createRow(rowIndex.getAndIncrement());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getPersoneelsnummer());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getOpdrachtnummer());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getFamilienaam() + ' ' + gewaarborgdLoonSupplement.getVoornaam());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getPeriode().toString());
        row.createCell(cellIndex++)
                .setCellValue(gewaarborgdLoonSupplement.getPrestatieverhouding().getTeller().toString().replace('.', ',') + '/' +
                        gewaarborgdLoonSupplement.getPrestatieverhouding().getNoemer().toString().replace('.', ','));
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getGelijkgesteldeCoefficient().doubleValue());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getEffectieveDagenCoefficient().doubleValue());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getVariabelLoonBedrag().doubleValue());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getTeller1Dagen());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getBedrag().doubleValue());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getEKalenderVerwerkt());
        row.createCell(cellIndex++)
                .setCellValue(gewaarborgdLoonSupplement.getEKalenderVerwerktDatum() != null ?
                        gewaarborgdLoonSupplement.getEKalenderVerwerktDatum().toString("dd-MM-yyyy HH:mm:ss") : null);
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getEKalenderVerwerktActor());
        row.createCell(cellIndex++).setCellValue(gewaarborgdLoonSupplement.getFout());
        row.createCell(cellIndex++)
                .setCellValue(
                        gewaarborgdLoonSupplement.getBerekenenTijdstip() != null ? gewaarborgdLoonSupplement.getBerekenenTijdstip().toString("dd-MM-yyyy HH:mm:ss") :
                                null);
        row.createCell(cellIndex).setCellValue(gewaarborgdLoonSupplement.getBerekenenGebruiker());
    }

    private void berekenenBedrag(
            Admin admin, Opdracht opdracht, LocalDateInterval monthUitbetaling, LocalDateInterval periode, LocalDateInterval periodeImport,
            LocalDateInterval periodeNlp, String actor) {
        Money bedragImport = Money.ZERO;
        int teller1DagenImport = 0;
        Prestatieverhouding pvhImport = null;
        List<GewaarborgdLoonSupplementImportDTO> importsByOpdrachtPeriode = new ArrayList<>();
        if (periodeImport != null) {
            importsByOpdrachtPeriode = this.findImportsByOpdrachtPeriode(admin, opdracht, periodeImport);
            if (!importsByOpdrachtPeriode.isEmpty()) {
                bedragImport =
                        new Money(importsByOpdrachtPeriode.stream().map(GewaarborgdLoonSupplementImportDTO::getBedrag).reduce(BigDecimal.ZERO, BigDecimal::add));
                teller1DagenImport = importsByOpdrachtPeriode.stream().mapToInt(GewaarborgdLoonSupplementImportDTO::getDagenTeller1).sum();
                pvhImport = getPrestatieverhouding(importsByOpdrachtPeriode);
            }
        }

        final Prestatieverhouding pvh = this.getPrestatieverhouding(opdracht, importsByOpdrachtPeriode, periode, periodeNlp);
        final BigDecimal gelijkgesteldeCoefficient = berekenGelijkgesteldeCoefficient(admin, opdracht.getId(), monthUitbetaling);
        if (gelijkgesteldeCoefficient.signum() != 0) {
            List<PrestatieverhoudingDetail> teller1DagenPerPvh =
                    getTeller1DagenPerPvh(admin, pvhImport, teller1DagenImport, periodeNlp, opdracht);
            int teller1Dagen = teller1DagenPerPvh.stream().map(PrestatieverhoudingDetail::getTeller1Dagen).reduce(0, Integer::sum);
            final BigDecimal effectieveDagenCoefficient =
                    berekenEffectieveDagenCoefficient(teller1DagenPerPvh, periode);
            if (effectieveDagenCoefficient.signum() != 0) {
                AardKodeExtensieGroepBO akeGroep =
                        aardKodeExtensieGroepBOService.getByDatum(admin, AardKodeExtensieGroepType.TOESLAG_RSZ_ONDERHEVIG, monthUitbetaling.getStart());
                if (akeGroep != null) {
                    final List<AardKodeExtensie> aardKodeExtensies =
                            akeGroep.getItems().stream().map(AardKodeExtensieGroepItemBO::getAardKodeExtensie).collect(Collectors.toList());
                    final Money uitbetaaldeSupplementen = bedragImport.add(berekenUitbetaaldeSupplementen(admin, opdracht, aardKodeExtensies, periodeNlp));
                    final Money bedrag = berekenBedrag(uitbetaaldeSupplementen, gelijkgesteldeCoefficient, effectieveDagenCoefficient, getAantalMaanden(periode));
                    final GewaarborgdLoonSupplement gewaarborgdLoonSupplement =
                            GewaarborgdLoonSupplementPO.create(opdracht, new YearMonth(monthUitbetaling.getStart()), pvh, teller1Dagen,
                                    new GewaarborgdLoonCoefficient(gelijkgesteldeCoefficient),
                                    new GewaarborgdLoonCoefficient(effectieveDagenCoefficient.setScale(5, RekenTools.DEFAULT_ROUNDING_MODE)),
                                    new VariabelLoonBedrag(uitbetaaldeSupplementen.round(5)),
                                    new GewaarborgdLoonSupplementBedrag(bedrag.round(5)),
                                    LocalDateTime.now(),
                                    actor);
                    log.info("opdrachtid: {}", gewaarborgdLoonSupplement.getOpdracht().getId());
                    log.info("gwl id: {}", gewaarborgdLoonSupplement.getId());
                    this.saveSupplement(admin, gewaarborgdLoonSupplement).ifPresent(gwl -> log.info("saved gwlid: {}", gwl.getId()));
                }
            }
        }
    }

    private List<PrestatieverhoudingDetail> getTeller1DagenPerPvh(
            Admin admin, Prestatieverhouding pvhImport, int teller1DagenImport, LocalDateInterval periodeNlp, Opdracht opdracht) {
        List<PrestatieverhoudingDetail> teller1DagenPerPvh = new ArrayList<>();
        if (teller1DagenImport > 0 && pvhImport != null) {
            teller1DagenPerPvh.add(new PrestatieverhoudingDetail(pvhImport, teller1DagenImport));
        }
        for (Opper opper : opdracht.getOpperSlices()) {
            if (periodeNlp != null && !opper.getActualTo().isBefore(periodeNlp.getStart()) && !opper.getActualFrom().isAfter(periodeNlp.getEnd())) {
                LocalDate startDatum = opper.getActualFrom().isBefore(periodeNlp.getStart()) ? periodeNlp.getStart() : opper.getActualFrom();
                LocalDate eindDatum = opper.getActualTo().isAfter(periodeNlp.getEnd()) ? periodeNlp.getEnd() : opper.getActualTo();
                LocalDateInterval periode = new LocalDateInterval(startDatum, eindDatum);
                int teller1Dagen = nlpPrestatieService.findByOpdrachtPeriode(admin, opdracht, periode).stream()
                        .filter(nlpPrestatie -> nlpPrestatie.getX().signum() != 0 && getAardKodeExtensie(nlpPrestatie).getTellerCode() == Tellerkode.GW)
                        .map(nlpPrestatie -> nlpPrestatie.getX().intValue()).reduce(0, Integer::sum);
                SleutelGegevensSingleOpper sleutelGegevensSingleOpper = new SleutelGegevensSingleOpper(opper);
                Breuk pvhBreuk = RkmPrestatieVerhouding.bepaalBreuk(sleutelGegevensSingleOpper, new RegulManagerImp());
                Prestatieverhouding prestatieverhouding = new Prestatieverhouding(pvhBreuk.getTeller(), pvhBreuk.getNoemer());
                teller1DagenPerPvh.add(new PrestatieverhoudingDetail(prestatieverhouding, teller1Dagen));
            }
        }
        return teller1DagenPerPvh;
    }

    private BigDecimal getAantalMaanden(LocalDateInterval periode) {
        return new BigDecimal(Months.monthsBetween(periode.getStart(), periode.getEnd()).getMonths() + 1);
    }

    private Money berekenBedrag(
            Money uitbetaaldeSupplementen, BigDecimal gelijkgesteldeCoefficient, BigDecimal effectieveDagenCoefficient, BigDecimal aantalMaanden) {
        return uitbetaaldeSupplementen.multiply(gelijkgesteldeCoefficient).divide(effectieveDagenCoefficient).divide(aantalMaanden);
    }

    private BigDecimal berekenGelijkgesteldeCoefficient(Admin admin, Integer opdrachtId, LocalDateInterval monthUitbetaling) {
        BigDecimal gelijkgesteldeCoefficient = BigDecimal.ZERO;
        Opdracht opdracht = opdrachtService.getByIdPeriode(admin, opdrachtId, monthUitbetaling);
        if (opdracht != null) {
            Prestatieverhouding pvh = getPrestatieverhouding(opdracht, new ArrayList<>(), monthUitbetaling, monthUitbetaling);
            BigDecimal prestatieverhouding = pvh.getTeller().divide(pvh.getNoemer(), RekenTools.MAX_SCALE, RekenTools.DEFAULT_ROUNDING_MODE);
            List<NlpPrestatie> nlpPrestaties =
                    nlpPrestatieService.findByOpdrachtPeriode(admin, opdracht, monthUitbetaling)
                            .stream()
                            .filter(nlpPrestatie -> nlpPrestatie.getX().signum() != 0)
                            .collect(Collectors.toList());
            List<AardKodeExtensie> aardKodeExtensies = aardKodeExtensieFacade.findByTellerCodes(Arrays.asList(2, 3, 4));
            nlpPrestaties = nlpPrestaties.stream()
                    .filter(nlpPrestatie -> (nlpPrestatie.getTijdperk().equals(2) && nlpPrestatie.getAard().equals(1) && nlpPrestatie.getCode().equals(103) &&
                            nlpPrestatie.getExtensie().equals(12))
                            || aardKodeExtensies.stream()
                            .anyMatch(aardKodeExtensie -> nlpPrestatie.getAard().equals(aardKodeExtensie.getAard()) &&
                                    nlpPrestatie.getCode().equals(aardKodeExtensie.getCode()) && nlpPrestatie.getExtensie().equals(aardKodeExtensie.getExtensie()) &&
                                    nlpPrestatie.getTijdperk().equals(aardKodeExtensie.getTijdperk())))
                    .collect(Collectors.toList());
            BigDecimal betaalPercentage = getBetaalPercentage(nlpPrestaties);
            if (betaalPercentage.signum() != 0) {
                BigDecimal sumX = nlpPrestaties.stream().map(NlpPrestatie::getX).reduce(BigDecimal.ZERO, BigDecimal::add);
                gelijkgesteldeCoefficient =
                        betaalPercentage.multiply(prestatieverhouding).multiply(sumX).divide(new BigDecimal(30), 5, RekenTools.DEFAULT_ROUNDING_MODE);
            }
        }
        return gelijkgesteldeCoefficient;
    }

    private BigDecimal getBetaalPercentage(List<NlpPrestatie> nlpPrestaties) {
        return nlpPrestaties.stream()
                .map(this::getBetaalPercentage)
                .reduce(BigDecimal.ZERO, BigDecimal::add)
                .divide(new BigDecimal(!nlpPrestaties.isEmpty() ? nlpPrestaties.size() : 1), RekenTools.MAX_SCALE, RekenTools.DEFAULT_ROUNDING_MODE);
    }

    private BigDecimal getBetaalPercentage(NlpPrestatie nlpPrestatie) {
        BigDecimal betaalPercentage = BigDecimal.ZERO;
        AardKodeExtensie aardKodeExtensie = getAardKodeExtensie(nlpPrestatie);
        switch (aardKodeExtensie.getTellerCode()) {
            case GW:
                if (isDayCode(aardKodeExtensie) && aardKodeExtensie.getCode() == 103 && aardKodeExtensie.getExtensie() == 12) {
                    betaalPercentage = BigDecimal.ONE;
                }
                break;
            case Z1:
                betaalPercentage = BigDecimal.ONE;
                break;
            case Z2:
                betaalPercentage = BETAAL_PERCENTAGE_8693;
                break;
            case Z34:
                betaalPercentage = BETAAL_PERCENTAGE_2693;
                break;
            default:
                break;
        }
        return betaalPercentage;
    }

    private AardKodeExtensie getAardKodeExtensie(NlpPrestatie nlpPrestatie) {
        return aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(
                nlpPrestatie.getTijdperk(), nlpPrestatie.getAard(), nlpPrestatie.getCode(), nlpPrestatie.getExtensie());
    }

    private BigDecimal berekenEffectieveDagenCoefficient(List<PrestatieverhoudingDetail> teller1DagenPerPvh, LocalDateInterval periode) {
        BigDecimal aantalDagen = getAantalMaanden(periode).multiply(new BigDecimal(30));
        return teller1DagenPerPvh.stream().map(pvh -> pvh.getPrestatieverhouding().getTeller()
                .divide(pvh.getPrestatieverhouding().getNoemer(), RekenTools.MAX_SCALE, RekenTools.DEFAULT_ROUNDING_MODE)
                .multiply(new BigDecimal(pvh.getTeller1Dagen()))
                .divide(aantalDagen, RekenTools.MAX_SCALE, RekenTools.DEFAULT_ROUNDING_MODE)).reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private Money berekenUitbetaaldeSupplementen(Admin admin, Opdracht opdracht, List<AardKodeExtensie> aardKodeExtensies, LocalDateInterval periode) {
        Money uitbetaaldeSupplementen = Money.ZERO;
        if (periode != null) {
            List<RekenHoofd> rekenHoofden = rekenResultatenService.findByOpdrachtPeriode(admin, opdracht, periode);
            List<RekenLijn> rekenLijnen = rekenHoofden.stream()
                    .flatMap(rekenHoofd -> rekenHoofd.getRekenLijnen().stream())
                    .filter(rekenLijn -> aardKodeExtensies.contains(rekenLijn.getAardKodeExtensie()))
                    .collect(Collectors.toList());
            List<RekenBedrag> rekenBedragen = rekenLijnen.stream().flatMap(rekenLijn -> rekenLijn.getRekenBedragen().stream()).collect(Collectors.toList());
            rekenBedragen =
                    rekenBedragen.stream().filter(rekenBedrag -> rekenBedrag.getBedragType().equals(RekenBedragType.BRUTO_MAANDLOON)).collect(Collectors.toList());
            uitbetaaldeSupplementen = rekenBedragen.stream().map(RekenBedrag::getBedrag).reduce(Money.ZERO, Money::add);
        }
        return uitbetaaldeSupplementen;
    }

    private Opdracht getOpdracht(Admin admin, Integer opdrachtId, String periode) {
