    }

    private String validateGewaarborgdLoonSupplement(Admin admin, GewaarborgdLoonSupplement gewaarborgdLoonSupplement) {
        String fout = "";
        if (gewaarborgdLoonSupplement.getBedrag() != null && gewaarborgdLoonSupplement.getBedrag().getValue().signum() == 0) {
            fout = "Gewaarborgd loon op supplementen met bedrag 0 kan niet overgedragen worden naar e-Kalender";
        } else if (gewaarborgdLoonSupplement.getEKalenderVerwerktDatum() != null) {
            fout = "Gewaarborgd loon op supplementen is al verwerkt in e-Kalender";
        } else {
            List<KalAfsluitenOpdracht> kalAfsluitenOpdrachten =
                    kalAfsluitenOpdrachtService.findByOpdrachtPeriode(admin, gewaarborgdLoonSupplement.getOpdracht(), gewaarborgdLoonSupplement.getPeriode(),
                            KalenderPrestatieKalender.KALENDER);
            if (!validatePrestatiecode(kalAfsluitenOpdrachten)) {
                fout = "Er is geen prestatiecode 1 aanwezig in de maand van overbrenging.";
            } else if (!validateKalenderStatus(kalAfsluitenOpdrachten)) {
                fout = "Status van e-Kalender moet nieuw, afgewerkt of afgesloten zijn.";
            }
        }
        return fout;
    }

    private void createKalOpdrachtLoonCode(Admin admin, GewaarborgdLoonSupplement gewaarborgdLoonSupplement, LocalDate datum) {
        AardKodeExtensie aardKodeExtensie = aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(2, 3, 101, 50);

        Opdracht opdracht = gewaarborgdLoonSupplement.getOpdracht();
        Pair<KalAfsluiten, KalAfsluitenOpdracht> kalAfsluitenKalAfsluitenOpdrachtPair =
                afsluitenService.creeerAfsluitObjectMetStatusNieuw(admin, KalenderPrestatieKalender.BEREKENDE_RESULTATEN, datum, opdracht);
        KalAfsluiten kalAfsluiten = kalAfsluitenKalAfsluitenOpdrachtPair.getFirst();
        KalAfsluitenOpdracht kalAfsluitenOpdracht = kalAfsluitenKalAfsluitenOpdrachtPair.getSecond();

        KalOpdrachtLooncode kalOpdrachtLooncode =
                KalOpdrachtLooncodeMapper.gewaarborgdLoonSupplementToPO(gewaarborgdLoonSupplement, aardKodeExtensie, kalAfsluiten, kalAfsluitenOpdracht, datum);

        Integer volgnr = kalOpdrachtLooncodeService.getVolgnr(admin, kalOpdrachtLooncode);
        kalOpdrachtLooncode.setVolgnr(volgnr);

        kalOpdrachtLooncodeService.create(admin, kalOpdrachtLooncode);
    }

    private boolean validateKalenderStatus(List<KalAfsluitenOpdracht> kalAfsluitenOpdrachten) {
        return kalAfsluitenOpdrachten.stream()
                .allMatch(kalAfsluitenOpdracht -> kalAfsluitenOpdracht.getStatus().equals(KalenderPrestatielijstStatus.AFGESLOTEN) ||
                        kalAfsluitenOpdracht.getStatus().equals(KalenderPrestatielijstStatus.NIEUW) ||
                        kalAfsluitenOpdracht.getStatus().equals(KalenderPrestatielijstStatus.GEREKEND));
    }

    private boolean validatePrestatiecode(List<KalAfsluitenOpdracht> kalAfsluitenOpdrachten) {
        return kalAfsluitenOpdrachten.stream()
                .flatMap(kalAfsluitenOpdracht -> kalAfsluitenOpdracht.getKalOpdrachtLooncodes().stream())
                .anyMatch(kalOpdrachtLooncode -> kalOpdrachtLooncode.getAardKodeExtensie().getPrestatieCode().equals(1));
    }
